      ..color = const Color(0xFFCBD5E1)
      ..strokeWidth = 2;
    _drawDashedLine(
      canvas,
      Offset(hitPoint.dx, boundaryY - 180),
      Offset(hitPoint.dx, boundaryY + 220),
      8,
