    final mediumLabelStyle = TextPainter(textDirection: TextDirection.ltr);
    mediumLabelStyle.text = const TextSpan(
      text: 'AIR  n = 1.00',
      style: TextStyle(
        color: Color(0xFF64748B),
        fontSize: 12,
        fontWeight: FontWeight.w700,
      ),
