    mediumLabelStyle.layout();
    mediumLabelStyle.paint(canvas, Offset(28, boundaryY - 34));

    mediumLabelStyle.text = TextSpan(
      text: 'WATER  n = ${refractiveIndex.toStringAsFixed(2)}',
      style: const TextStyle(
