      color: const Color(0xFFF97316),
    );

    if (state.mode == _RayMode.refract) {
      final refractedEnd = Offset(
        hitPoint.dx + math.sin(state.refractedRadians!) * 280,
        hitPoint.dy - math.cos(state.refractedRadians!) * 280,
