          (hitPoint.dy + reflectedEnd.dy) / 2 + 14,
        ),
        color: const Color(0xFFFDE047),
      );
      _drawAngleArc(
        canvas,
        center: hitPoint,
        radius: 56,
        start: -math.pi / 2,
        sweep: state.incidentRadians,
        color: const Color(0xFFF97316),
