        _drawAngleArc(
          canvas,
          center: hitPoint,
          radius: 56,
          start: -math.pi / 2,
          sweep: state.incidentRadians,
          color: const Color(0xFFF97316),
          label: 'i = ic',
        );
      }
    }

    final hitPaint = Paint()..color = Colors.white;
    canvas.drawCircle(hitPoint, 6, hitPaint);
